     7→
     8→import "google/protobuf/duration.proto";
     9→import "google/protobuf/struct.proto";
    10→import "google/protobuf/wrappers.proto";
    11→
    12→import "udpa/annotations/status.proto";
    13→import "validate/validate.proto";
    14→
    15→option java_package = "io.envoyproxy.envoy.extensions.access_loggers.fluentd.v3";
    16→option java_outer_classname = "FluentdProto";
    17→option java_multiple_files = true;
    18→option go_package = "github.com/envoyproxy/go-control-plane/envoy/extensions/access_loggers/fluentd/v3;fluentdv3";
    19→option (udpa.annotations.file_status).package_version_status = ACTIVE;
    20→
    21→// [#protodoc-title: Fluentd access log]
    22→
    23→// Configuration for the *envoy.access_loggers.fluentd* :ref:`AccessLog <envoy_v3_api_msg_config.accesslog.v3.AccessLog>`.
    24→// This access log extension will send the emitted access logs over a TCP connection to an upstream that is accepting
    25→// the Fluentd Forward Protocol as described in: `Fluentd Forward Protocol Specification
    26→// <https://github.com/fluent/fluentd/wiki/Forward-Protocol-Specification-v1>`_.
    27→// [#extension: envoy.access_loggers.fluentd]
    28→// [#next-free-field: 9]
    29→message FluentdAccessLogConfig {
    30→  message RetryOptions {
    31→    // The number of times the logger will attempt to connect to the upstream during reconnects.
    32→    // By default, there is no limit. The logger will attempt to reconnect to the upstream each time
    33→    // connecting to the upstream failed or the upstream connection had been closed for any reason.
    34→    google.protobuf.UInt32Value max_connect_attempts = 1;
    35→
    36→    // Sets the backoff strategy. If this value is not set, the default base backoff interval is 500
    37→    // milliseconds and the default max backoff interval is 5 seconds (10 times the base interval).
    38→    config.core.v3.BackoffStrategy backoff_options = 2;
    39→  }
    40→
    41→  // The upstream cluster to connect to for streaming the Fluentd messages.
    42→  string cluster = 1 [(validate.rules).string = {min_len: 1}];
    43→
    44→  // A tag is a string separated with '.' (e.g. log.type) to categorize events.
    45→  // See: https://github.com/fluent/fluentd/wiki/Forward-Protocol-Specification-v1#message-modes
    46→  string tag = 2 [(validate.rules).string = {min_len: 1}];
    47→
    48→  // The prefix to use when emitting :ref:`statistics <config_access_log_stats>`.
    49→  string stat_prefix = 3 [(validate.rules).string = {min_len: 1}];
    50→
    51→  // Interval for flushing access logs to the TCP stream. Logger will flush requests every time
    52→  // this interval is elapsed, or when batch size limit is hit, whichever comes first. Defaults to
    53→  // 1 second.
    54→  google.protobuf.Duration buffer_flush_interval = 4 [(validate.rules).duration = {gt {}}];
    55→
    56→  // Soft size limit in bytes for access log entries buffer. The logger will buffer requests until
    57→  // this limit it hit, or every time flush interval is elapsed, whichever comes first. When the buffer
