   108→bool StatusCodeFilter::evaluate(const Formatter::HttpFormatterContext&,
   109→                                const StreamInfo::StreamInfo& info) const {
   110→  if (!info.responseCode()) {
   111→    return compareAgainstValue(0ULL);
