   128→RuntimeFilter::RuntimeFilter(const envoy::config::accesslog::v3::RuntimeFilter& config,
   129→                             Runtime::Loader& runtime, Random::RandomGenerator& random)
   130→    : runtime_(runtime), random_(random), runtime_key_(config.runtime_key()),
   131→      percent_(config.percent_sampled()),
   132→      use_independent_randomness_(config.use_independent_randomness()) {}
   133→
   134→bool RuntimeFilter::evaluate(const Formatter::HttpFormatterContext&,
   135→                             const StreamInfo::StreamInfo& stream_info) const {
   136→  // This code is verbose to avoid preallocating a random number that is not needed.
   137→  uint64_t random_value;
   138→  if (use_independent_randomness_) {
   139→    random_value = random_.random();
   140→  } else if (!stream_info.getStreamIdProvider().has_value()) {
   141→    random_value = random_.random();
   142→  } else {
   143→    const auto rid_to_integer = stream_info.getStreamIdProvider()->toInteger();
   144→    if (!rid_to_integer.has_value()) {
   145→      random_value = random_.random();
   146→    } else {
   147→      random_value =
   148→          rid_to_integer.value() %
   149→          ProtobufPercentHelper::fractionalPercentDenominatorToInt(percent_.denominator());
   150→    }
   151→  }
   152→
   153→  return runtime_.snapshot().featureEnabled(
   154→      runtime_key_, percent_.numerator(), random_value,
   155→      ProtobufPercentHelper::fractionalPercentDenominatorToInt(percent_.denominator()));
   156→}
