   219→ResponseFlagFilter::ResponseFlagFilter(
   220→    const envoy::config::accesslog::v3::ResponseFlagFilter& config)
   221→    : has_configured_flags_(!config.flags().empty()) {
   222→
   223→  // Preallocate the vector to avoid frequent heap allocations.
   224→  configured_flags_.resize(StreamInfo::ResponseFlagUtils::responseFlagsVec().size(), false);
   225→  for (int i = 0; i < config.flags_size(); i++) {
   226→    auto response_flag = StreamInfo::ResponseFlagUtils::toResponseFlag(config.flags(i));
   227→    // The config has been validated. Therefore, every flag in the config will have a mapping.
   228→    ASSERT(response_flag.has_value());
   229→
   230→    // The vector is allocated with the size of the response flags vec. Therefore, the index
   231→    // should always be valid.
   232→    ASSERT(response_flag.value().value() < configured_flags_.size());
   233→
   234→    configured_flags_[response_flag.value().value()] = true;
   235→  }
   236→}
