   238→bool ResponseFlagFilter::evaluate(const Formatter::HttpFormatterContext&,
   239→                                  const StreamInfo::StreamInfo& info) const {
   240→  if (has_configured_flags_) {
   241→    for (const auto flag : info.responseFlags()) {
   242→      ASSERT(flag.value() < configured_flags_.size());
   243→      if (configured_flags_[flag.value()]) {
   244→        return true;
   245→      }
   246→    }
   247→    return false;
   248→  }
   249→  return info.hasAnyResponseFlag();
   250→}
