   260→bool GrpcStatusFilter::evaluate(const Formatter::HttpFormatterContext& context,
   261→                                const StreamInfo::StreamInfo& info) const {
   262→
   263→  Grpc::Status::GrpcStatus status = Grpc::Status::WellKnownGrpcStatus::Unknown;
   264→  const auto& optional_status =
   265→      Grpc::Common::getGrpcStatus(context.responseTrailers(), context.responseHeaders(), info);
   266→  if (optional_status.has_value()) {
   267→    status = optional_status.value();
   268→  }
   269→
   270→  const bool found = statuses_.find(status) != statuses_.end();
   271→  return exclude_ ? !found : found;
   272→}
