   331→InstanceSharedPtr AccessLogFactory::fromProto(const envoy::config::accesslog::v3::AccessLog& config,
   332→                                              Server::Configuration::FactoryContext& context) {
   333→  FilterPtr filter;
   334→  if (config.has_filter()) {
   335→    filter = FilterFactory::fromProto(config.filter(), context);
   336→  }
   337→
   338→  auto& factory = Config::Utility::getAndCheckFactory<AccessLog::AccessLogInstanceFactory>(config);
   339→  ProtobufTypes::MessagePtr message = Config::Utility::translateToFactoryConfig(
   340→      config, context.messageValidationVisitor(), factory);
   341→
   342→  return factory.createAccessLogInstance(*message, std::move(filter), context);
